  ('elementary-e0adf6cd-moex-00923', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '在撰寫教育研究計畫時，如果將智力定義為「藉由比西智力測驗所獲得的分數，分數越高，代表智力越 高」，此種定義屬下列何者？', '["概念性定義", "結構性定義", "系統性定義", "操作性定義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "e26dd343fba8", "answer_pdf_sha1": "df8736c82333", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
